7477	\begin{lemma}
7478	[A contracting homotopy of the identity makes homology vanish]
7479	  \label{lem:isZero_homology_of_homotopy_id_zero}
7480	  \lean{AlgebraicGeometry.isZero_homology_of_homotopy_id_zero}
7481	  Let \(\mathcal{A}\) be a preadditive category and \(D^\bullet\) a cochain complex in
7482	  \(\mathcal{A}\). If there is a homotopy \(\mathrm{id}_{D^\bullet} \simeq 0\) between the
7483	  identity endomorphism of \(D^\bullet\) and the zero endomorphism, then for every degree
7484	  \(p\) the homology object \(H^p(D^\bullet)\) is a zero object.
7485	\end{lemma}
7486	\begin{proof}
7487	  The map induced on homology is a homotopy invariant: homotopic chain maps induce equal
7488	  maps on each homology object. Applying this to the homotopy \(\mathrm{id}_{D^\bullet}
7489	  \simeq 0\), the map induced by \(\mathrm{id}_{D^\bullet}\) on \(H^p(D^\bullet)\) equals the
7490	  map induced by \(0\). The former is \(\mathrm{id}_{H^p(D^\bullet)}\) (homology is a
7491	  functor) and the latter is the zero endomorphism of \(H^p(D^\bullet)\); hence
7492	  \(\mathrm{id}_{H^p(D^\bullet)} = 0\). An object whose identity morphism equals its zero
7493	  endomorphism is a zero object, so \(H^p(D^\bullet)\) is zero.
7494	\end{proof}
