7580	\begin{lemma}
7581	[Sections of one push--pull leg over an open]
7582	  \label{lem:pushPull_leg_sections}
7583	  \lean{AlgebraicGeometry.pushPull_leg_sections}
7584	  \uses{def:push_pull_obj, def:cech_free_presheaf_complex, lem:pushforward_obj_obj_mathlib,
7585	    lem:restrictFunctorIsoPullback_mathlib, lem:restrict_obj_mathlib}
7586	  Let \(j_\sigma : U_\sigma \hookrightarrow X\) be the open immersion of the intersection
7587	  open \(U_\sigma = \operatorname{coverInterOpen}\mathcal{U}\,\sigma\), and let
7588	  \(V \subseteq X\) be an open. Then there is a natural isomorphism of section groups
7589	  \[
7590	    \Gamma\bigl(V,\, \operatorname{pushPullObj}\mathcal{F}\,(\operatorname{Over.mk}
7591	      j_\sigma)\bigr)
7592	      \;\cong\;
7593	    \Gamma\bigl(U_\sigma \cap V,\, \mathcal{F}\bigr).
7594	  \]
7595	\end{lemma}
7596	\begin{proof}
7597	  \uses{lem:pushforward_obj_obj_mathlib, lem:restrictFunctorIsoPullback_mathlib,
7598	    lem:restrict_obj_mathlib}
7599	  This follows from three standard identifications. First, the leg is
7600	  \((j_\sigma)_*\,(j_\sigma)^*\mathcal{F}\); pushforward sections are computed by preimage,
7601	  \(\Gamma\bigl(V, (j_\sigma)_* N\bigr) = \Gamma\bigl(j_\sigma^{-1}(V), N\bigr)\)
7602	  (Lemma~\ref{lem:pushforward_obj_obj_mathlib}, an equality), applied with \(N =
7603	  (j_\sigma)^*\mathcal{F}\). Second, pullback along the open immersion \(j_\sigma\) is the
7604	  restriction functor: \((j_\sigma)^*\mathcal{F} \cong \mathcal{F}.\operatorname{restrict}
7605	  j_\sigma\) by Lemma~\ref{lem:restrictFunctorIsoPullback_mathlib}. Third, the sections of a
7606	  restricted module over \(j_\sigma^{-1}(V)\) are the sections of \(\mathcal{F}\) over the
7607	  image open (Lemma~\ref{lem:restrict_obj_mathlib}, an equality): \(\Gamma\bigl(j_\sigma^{-1}
7608	  (V), \mathcal{F}.\operatorname{restrict} j_\sigma\bigr) = \Gamma\bigl(j_\sigma\bigl(
7609	  j_\sigma^{-1}(V)\bigr), \mathcal{F}\bigr) = \Gamma\bigl(U_\sigma \cap V, \mathcal{F}\bigr)\),
7610	  the last equality because the image of the preimage of \(V\) under the open immersion
7611	  \(j_\sigma : U_\sigma \hookrightarrow X\) is exactly \(U_\sigma \cap V\). Composing the
7612	  three gives the stated isomorphism.
7613	\end{proof}
