7615	\begin{lemma}
7616	[Degreewise section identification of the {\v C}ech backbone]
7617	  \label{lem:pushPull_eval_prod_iso}
7618	  \lean{AlgebraicGeometry.pushPull_eval_prod_iso}
7619	  \uses{lem:pushPull_sigma_iso, lem:pushPull_leg_sections,
7620	    lem:evaluation_preserves_products_mathlib}
7621	  For an open \(V \subseteq X\) and every degree \(p\) there is an isomorphism
7622	  \[
7623	    \Gamma\bigl(V,\, \operatorname{pushPullObj}\mathcal{F}\,Y_p\bigr)
7624	      \;\cong\;
7625	    \prod_{\sigma : \mathrm{Fin}(p+1) \to I}
7626	      \Gamma\bigl(\operatorname{coverInterOpen}\mathcal{U}\,\sigma \cap V,\, \mathcal{F}\bigr).
7627	  \]
7628	\end{lemma}
7629	\begin{proof}
7630	  \uses{lem:pushPull_sigma_iso, lem:pushPull_leg_sections,
7631	    lem:evaluation_preserves_products_mathlib}
7632	  Combine the product decomposition of the backbone push--pull object
7633	  (Lemma~\ref{lem:pushPull_sigma_iso}), \(\operatorname{pushPullObj}\mathcal{F}\,Y_p \cong
7634	  \prod_\sigma \operatorname{pushPullObj}\mathcal{F}\,(\operatorname{Over.mk} j_\sigma)\),
7635	  with the fact that the section (evaluation-at-\(V\)) functor on \(X.\mathrm{Modules}\)
7636	  preserves products (Lemma~\ref{lem:evaluation_preserves_products_mathlib}): \(\Gamma(V,
7637	  \prod_\sigma N_\sigma) \cong \prod_\sigma \Gamma(V, N_\sigma)\). This reduces the
7638	  left-hand side to \(\prod_\sigma \Gamma\bigl(V, \operatorname{pushPullObj}\mathcal{F}\,
7639	  (\operatorname{Over.mk} j_\sigma)\bigr)\), and the per-leg section identification
7640	  (Lemma~\ref{lem:pushPull_leg_sections}) rewrites each factor as \(\Gamma(U_\sigma \cap V,
7641	  \mathcal{F})\).
7642	\end{proof}
