7678	\begin{lemma}
7679	[The section {\v C}ech complex inside a cover member is contractible]
7680	  \label{lem:cechSection_contractible}
7681	  \lean{AlgebraicGeometry.cechSection_contractible}
7682	  \uses{lem:cechSection_complex_iso, lem:cech_acyclic_affine, lem:cech_engine_complex,
7683	    def:cech_free_presheaf_complex}
7684	  Suppose \(V \le \operatorname{coverOpen}\mathcal{U}\,i_{\mathrm{fix}}\) for some fixed index
7685	  \(i_{\mathrm{fix}}\), i.e.\ \(V\) lies inside one cover member. Then the concrete section
7686	  {\v C}ech complex \(D'^\bullet\) of Lemma~\ref{lem:cechSection_complex_iso} over the family
7687	  \(U'_j = \operatorname{coverInterOpen}\mathcal{U}\,j \cap V\) admits a contracting homotopy
7688	  \(\mathrm{id}_{D'^\bullet} \simeq 0\).
7689	\end{lemma}
7690	\begin{proof}
7691	  \uses{lem:cech_acyclic_affine, lem:cech_engine_complex}
7692	  Because \(V \le U_{i_{\mathrm{fix}}}\), the restricted family \(U'_j = U_j \cap V\) has a
7693	  \emph{maximum}: \(U'_{i_{\mathrm{fix}}} = U_{i_{\mathrm{fix}}} \cap V = V\), and every
7694	  \(U'_j \le V\). Consequently, for each multi-index \(\sigma\),
7695	  \(U'_{i_{\mathrm{fix}}\,\sigma} = U_{i_{\mathrm{fix}}} \cap U_\sigma \cap V = U_\sigma \cap
7696	  V = U'_\sigma\): prepending the index \(i_{\mathrm{fix}}\) does not change the open, so the
7697	  prepend map is the \emph{identity} on each coefficient \(\Gamma(U'_\sigma, \mathcal{F})\)
7698	  (the membership criterion \(\operatorname{le\_coverInterOpen\_iff}\) of
7699	  Lemma~\ref{lem:cech_engine_complex}). The dependent-coefficient combinatorial {\v C}ech
7700	  engine --- \(\operatorname{depDiff}\), \(\operatorname{depHomotopy}\),
7701	  \(\operatorname{depHomotopy\_spec}\), \(\operatorname{depDiff\_exact}\) of
7702	  Lemma~\ref{lem:cech_acyclic_affine} --- then supplies the prepend-\(i_{\mathrm{fix}}\)
7703	  contracting homotopy \(h\) with \(d \circ h + h \circ d = \mathrm{id}\), since its unit,
7704	  shift, and coface-commutation compatibilities all hold with the prepend map acting as the
7705	  identity. Packaging \(h\) as a homotopy of cochain complexes gives \(\mathrm{id}_{D'^\bullet}
7706	  \simeq 0\).
7707	\end{proof}
