7709	\begin{lemma}
7710	[Local vanishing of the evaluated augmented {\v C}ech homology]
7711	  \label{lem:cechSection_isZero_homology}
7712	  \lean{AlgebraicGeometry.cechSection_isZero_homology}
7713	  \uses{lem:cechSection_complex_iso, lem:cechSection_contractible,
7714	    lem:isZero_homology_of_homotopy_id_zero}
7715	  Let \(V \le \operatorname{coverOpen}\mathcal{U}\,i\) for some index \(i\). Then for every
7716	  degree \(p\) the homology \(H^p(D^\bullet)\) of the augmented {\v C}ech complex evaluated at
7717	  \(V\) (the complex \(D^\bullet\) of Lemma~\ref{lem:cechSection_complex_iso}) is a zero
7718	  object; equivalently \(D^\bullet\) carries a contracting homotopy \(\mathrm{id}_{D^\bullet}
7719	  \simeq 0\). This is the residual obligation of Step~3 of
7720	  Lemma~\ref{lem:cech_augmented_resolution}.
7721	\end{lemma}
7722	\begin{proof}
7723	  \uses{lem:cechSection_complex_iso, lem:cechSection_contractible,
7724	    lem:isZero_homology_of_homotopy_id_zero}
7725	  By Lemma~\ref{lem:cechSection_complex_iso} the evaluated complex \(D^\bullet\) is
7726	  isomorphic to the concrete section {\v C}ech complex \(D'^\bullet\). The hypothesis \(V \le
7727	  \operatorname{coverOpen}\mathcal{U}\,i\) places \(V\) inside one cover member, so
7728	  Lemma~\ref{lem:cechSection_contractible} gives a contracting homotopy \(\mathrm{id}_{D'^\bullet}
7729	  \simeq 0\); transporting it across the complex isomorphism yields \(\mathrm{id}_{D^\bullet}
7730	  \simeq 0\). Lemma~\ref{lem:isZero_homology_of_homotopy_id_zero} then makes
7731	  \(H^p(D^\bullet)\) a zero object in every degree.
7732	\end{proof}
