7736	\begin{lemma}[Pushforward sections are sections over the preimage]
7737	  \label{lem:pushforward_obj_obj_mathlib}
7738	  \lean{AlgebraicGeometry.Scheme.Modules.pushforward_obj_obj}
7739	  \mathlibok
7740	  \textit{Provided by Mathlib.}
7741	  For a morphism \(f : X \to Y\), an \(\mathcal{O}_X\)-module \(\mathcal{M}\), and an open
7742	  \(U \subseteq Y\), the sections of the pushforward \(f_*\mathcal{M}\) over \(U\) coincide
7743	  definitionally with the sections of \(\mathcal{M}\) over the preimage:
7744	  \(\Gamma(U, f_*\mathcal{M}) = \Gamma(f^{-1}(U), \mathcal{M})\).
7745	\end{lemma}
