7747	\begin{lemma}[Pullback along an open immersion is the restriction functor]
7748	  \label{lem:restrictFunctorIsoPullback_mathlib}
7749	  \lean{AlgebraicGeometry.Scheme.Modules.restrictFunctorIsoPullback}
7750	  \mathlibok
7751	  \textit{Provided by Mathlib.}
7752	  For an open immersion \(f : X \to Y\), the restriction functor
7753	  \(\operatorname{restrictFunctor} f : Y.\mathrm{Modules} \to X.\mathrm{Modules}\) is
7754	  naturally isomorphic to the module pullback functor \(f^* = \operatorname{pullback} f\). In
7755	  particular \(f^*\mathcal{M} \cong \mathcal{M}.\operatorname{restrict} f\) for every
7756	  \(\mathcal{O}_Y\)-module \(\mathcal{M}\).
7757	\end{lemma}
