7759	\begin{lemma}[Evaluation of a sheaf of modules preserves products]
7760	  \label{lem:evaluation_preserves_products_mathlib}
7761	  \lean{SheafOfModules.evaluationPreservesLimitsOfShape}
7762	  \mathlibok
7763	  \textit{Provided by Mathlib.}
7764	  For a sheaf of rings on a site and any object \(U\), the evaluation (sections-at-\(U\))
7765	  functor \(\operatorname{evaluation}\,U : \operatorname{SheafOfModules} \to \mathrm{Ab}\)
7766	  preserves limits of every shape; in particular it preserves products, so \(\Gamma(U,
7767	  \prod_\sigma N_\sigma) \cong \prod_\sigma \Gamma(U, N_\sigma)\).
7768	\end{lemma}
