7770	\begin{lemma}[Sections over a binary coproduct scheme are a product]
7771	  \label{lem:coprodPresheafObjIso_mathlib}
7772	  \lean{AlgebraicGeometry.Scheme.coprodPresheafObjIso}
7773	  \mathlibok
7774	  \textit{Provided by Mathlib.}
7775	  For schemes \(X, Y\) and an open \(U\) of the coproduct \(X \amalg Y\), the structure-sheaf
7776	  sections over \(U\) decompose as the product of the sections over the two preimages:
7777	  \((X \amalg Y).\mathcal{O}(U) \cong X.\mathcal{O}(\operatorname{inl}^{-1} U) \times
7778	  Y.\mathcal{O}(\operatorname{inr}^{-1} U)\). This is the binary disjoint-union sheaf
7779	  decomposition that Lemma~\ref{lem:pushPull_sigma_iso} ports to the indexed,
7780	  \(\operatorname{SheafOfModules}\) setting.
7781	\end{lemma}
