7783	\begin{lemma}[Sections of a sheaf over a disjoint union are a product]
7784	  \label{lem:isProductOfDisjoint_mathlib}
7785	  \lean{TopCat.Sheaf.isProductOfDisjoint}
7786	  \mathlibok
7787	  \textit{Provided by Mathlib.}
7788	  For a sheaf \(F\) (valued in a category with products) on a topological space and two opens
7789	  \(U, V\) with \(U \sqcap V = \bot\) (disjoint), the sections over the union are the product
7790	  of the sections: \(F(U \sqcup V) \cong F(U) \times F(V)\). Iterated over a finite family,
7791	  this is the disjoint-union decomposition underlying Lemma~\ref{lem:pushPull_sigma_iso}.
7792	\end{lemma}
